    val dialogBinding = DialogUserAgentBinding.inflate(layoutInflater)                        dialogBinding.userAgentTextBox.setText(                            PrefManager.getVal(PrefName.DefaultUserAgent)                        )                        customAlertDialog().apply {                            setTitle(R.string.user_agent)                            setCustomView(dialogBinding.root)                            setPosButton(R.string.ok) {                                PrefManager.setVal(                                    PrefName.DefaultUserAgent,                                    dialogBinding.userAgentTextBox.text.toString()                                )                            }
