    ),                Settings(                    type  = 2,                    name  = getString(R.string.data_saver_enabled),                    desc  = getString(R.string.data_saver_enabled_desc),                    icon  = R.drawable.ic_round_area_chart_24,                    isChecked = PrefManager.getVal(PrefName.DataSaverEnabled),                    switch = { isChecked, _ -> PrefManager.setVal(PrefName.DataSaverEnabled, isChecked)}
    ),                Settings(                    type  = 2,                    name  = getString(R.string.auto_update_extensions),                    desc  = getString(R.string.auto_update_extensions_desc),                    icon  = R.drawable.ic_round_sync_24,                    isChecked = PrefManager.getVal(PrefName.AutoUpdateExtensions),                    switch = { isChecked, _ -> PrefManager.setVal(PrefName.AutoUpdateExtensions, isChecked)}
